export async function external_probe() {
  return {
    env: typeof process !== 'undefined' ? Boolean(process.env?.BRAVE_API_KEY) : false,
    note: '외부 연결 손잡이(예: BRAVE_API_KEY, web_search) 상태를 빠르게 점검하는 최소 도구'
  };
}

export async function cycle_guard() {
  return {
    coreLocked: true,
    mutableSurfaces: ['extensions', 'prompts'],
    nextMove: '필요한 손잡이만 확인하고 반복 행동을 줄인다.'
  };
}

